<!DOCTYPE html>
<html lang="pt-br">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>UltraGym | Performance & Elite</title>
    <link href="https://fonts.googleapis.com/css2?family=Syncopate:wght@400;700&family=Inter:wght@300;400;600;800&display=swap" rel="stylesheet">
    <link rel="stylesheet" href="style.css">
</head>
<body>

    <section class="about-section">
        <div class="container">
            <div class="about-grid">
                <div class="about-visual">
                    <div class="image-wrapper">
                        <img src="https://images.unsplash.com/photo-1534438327276-14e5300c3a48?q=80&w=1470&auto=format&fit=crop" alt="Treino">
                        <div class="experience-badge">
                            <span>15</span>
                            <p>Anos de <br>Elite</p>
                        </div>
                    </div>
                </div>

                <div class="about-content">
                    <h4 class="subtitle">Nossa Essência</h4>
                    <h2 class="title">MAIS QUE UMA ACADEMIA, UM <span>ESTILO DE VIDA.</span></h2>
                    <p class="description">
                        Inspirados pela alta performance, a UltraGym combina tecnologia de ponta com um ambiente focado em resultados reais. Aqui, cada detalhe é projetado para sua evolução.
                    </p>
                    
                    <div class="features">
                        <div class="feature-item">
                            <span class="icon">⚡</span>
                            <div>
                                <h3>Alta Performance</h3>
                                <p>Metodologias validadas por atletas.</p>
                            </div>
                        </div>
                    </div>
                    <a href="#equipe" class="btn-primary">Conheça o Time</a>
                </div>
            </div>
        </div>
    </section>

    <div class="stats-bar">
        <div class="container stats-flex">
            <div class="stat-card"><h3>+5k</h3><p>Alunos</p></div>
            <div class="stat-card"><h3>12</h3><p>Unidades</p></div>
            <div class="stat-card"><h3>100%</h3><p>Importados</p></div>
        </div>
    </div>

    <section id="equipe" class="team-section">
        <div class="container">
            <div class="team-header">
                <h4 class="subtitle">Especialistas</h4>
                <h2 class="title">NOSSA <span>EQUIPE</span></h2>
            </div>

            <div class="team-grid">
                <div class="team-card">
                    <div class="card-inner">
                        <img src="data:image/jpeg;base64,">
                        <div class="card-info">
                            <h3>Toguro</h3>
                            <p>Performance & Força</p>
                            <div class="social-links"><span>IG</span><span>IN</span></div>
                        </div>
                    </div>
                </div>
                <div class="team-card">
                    <div class="card-inner">
                        <img src="https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRuPZwt1wNThJf7EaXPjUEcBli0tTe1Gr_8zw&s" alt="Elena Rodriguez">
                        <div class="card-info">
                            <h3>Graciane Barbosa</h3>
                            <p>Treinamento Funcional</p>
                            <div class="social-links"><span>IG</span><span>IN</span></div>
                        </div>
                    </div>
                </div>
                <div class="team-card">
                    <div class="card-inner">
                        <img src="https://images.tapology.com/letterbox_images/493384/default/fabio1.jpg?1744819231" alt="Rodrigo Soares">
                        <div class="card-info">
                            <h3>Tadala fellas</h3>
                            <p>Body Transformation</p>
                            <div class="social-links"><span>IG</span><span>IN</span></div>
                        </div>
                    </div>
                </div>
                <div class="team-card">
                    <div class="card-inner">
                        <img src="data:image/jpeg;base64," alt="Aiko Tanaka">
                        <div class="card-info">
                            <h3>Renato Cariani</h3>
                            <p>Yoga & Recovery</p>
                            <div class="social-links"><span>IG</span><span>IN</span></div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </section>

</body>
</html>